const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

function getEnv(name, fallback = undefined) {
  const value = process.env[name] ?? fallback;
  if (value === undefined || value === null || value === '') {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function initSendGrid() {
  const apiKey = getEnv('SENDGRID_API_KEY');
  sgMail.setApiKey(apiKey);
  return sgMail;
}

function initTwilio() {
  const accountSid = getEnv('TWILIO_ACCOUNT_SID');
  const authToken = getEnv('TWILIO_AUTH_TOKEN');
  return twilio(accountSid, authToken);
}

function validateEmailPayload(payload) {
  const { to, from, subject, text, html } = payload || {};
  if (!to) throw new Error('Missing required field: to');
  if (!from) throw new Error('Missing required field: from');
  if (!subject) throw new Error('Missing required field: subject');
  if (!text && !html) throw new Error('Provide at least one of text or html');
  return { to, from, subject, text, html };
}

function validateSmsPayload(payload) {
  const { to, from, body } = payload || {};
  if (!to) throw new Error('Missing required field: to');
  if (!from) throw new Error('Missing required field: from');
  if (!body) throw new Error('Missing required field: body');
  return { to, from, body };
}

exports.sendNotification = async (req, res) => {
  res.set('Content-Type', 'application/json');

  try {
    const body = typeof req.body === 'string' ? JSON.parse(req.body) : (req.body || {});
    const type = body.type;

    if (!type || !['email', 'sms', 'both'].includes(type)) {
      return res.status(400).json({
        ok: false,
        error: 'Invalid or missing type. Expected email, sms, or both.'
      });
    }

    const results = {};
    const sendgrid = type === 'email' || type === 'both' ? initSendGrid() : null;
    const twilioClient = type === 'sms' || type === 'both' ? initTwilio() : null;

    if (type === 'email' || type === 'both') {
      const emailPayload = validateEmailPayload(body.email || body);
      const message = {
        to: emailPayload.to,
        from: emailPayload.from,
        subject: emailPayload.subject,
        text: emailPayload.text,
        html: emailPayload.html
      };

      const [response] = await sendgrid.send(message);
      results.email = {
        accepted: true,
        statusCode: response.statusCode,
        messageId: response.headers['x-message-id'] || null
      };
    }

    if (type === 'sms' || type === 'both') {
      const smsPayload = validateSmsPayload(body.sms || body);
      const message = await twilioClient.messages.create({
        to: smsPayload.to,
        from: smsPayload.from,
        body: smsPayload.body
      });

      results.sms = {
        accepted: true,
        sid: message.sid,
        status: message.status
      };
    }

    return res.status(200).json({
      ok: true,
      results
    });
  } catch (err) {
    console.error('Notification delivery error:', err);

    const statusCode = err.message && err.message.startsWith('Missing required field') ? 400 : 500;

    return res.status(statusCode).json({
      ok: false,
      error: err.message || 'Internal Server Error'
    });
  }
};